INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 122511, 1, 0, "むっ…なんだ？\nこの獲物を狙う猛禽のような殺気は？\n誰かいるのか？", 11, 0.5, 943, 19430038, 5, 0);
