INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 107911, 1, 0, "なんだ、ユカリだったかにゃ。\n何ってもちろん商売にゃ！", 11, 1, 944, 19440033, 10, 0);
