INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (1, 1, "45_yui_shy_loop", 0.1, "45_yui_shy_in", 3, "", 945, 19450031, 0, 0.1);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", "vo_fpc", 0, "", "vo_fpc_30504", 21, "", 945, 19450032, "", "");
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 122611, 1, 0, "…うん、やっちゃった…\nおっきなハートマーク…\nやっぱりこれは無しで！\nマコトちゃん食べてくれる！？", 11, 1, 945, 19450033, 5, 0);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", 0, "", "", "", 91, "", 945, 19450034, "", "");
